use reth_tracing::{
    tracing_subscriber::filter::Directive, FileInfo, FileWorkerGuard, LayerInfo, LogFormat,
    RethTracer, RitualRouter, Tracer,
};

fn init_ritual_tracing(&self, filter: &str) -> eyre::Result<Option<FileWorkerGuard>> {
    let router = RitualRouter::new(
        vec!["ritual::tx::lifecycle", "ritual::block::lifecycle", "ritual::scheduling"],
        filter,
    );
    let lifecycle_guard = router.init()?;
    if self.log_file_max_files > 0 {
        let info = self.file_info();
        let file = self.layer(self.log_file_format, self.log_file_filter.clone(), false);
        let mut file_tracer = RethTracer::new();
        file_tracer = file_tracer.with_file(file, info);
        return file_tracer.init();
    }
    Ok(lifecycle_guard)
}

pub fn init_tracing(&self) -> eyre::Result<Option<FileWorkerGuard>> {
    let filter = &self.log_stdout_filter;
    if filter.contains("ritual::") {
        return self.init_ritual_tracing(filter);
    }
    let mut tracer = RethTracer::new();
    /* standard tracing setup */
}
